INSERT OR IGNORE INTO posts (id, bbsid, board_id, user_id, title, content, content_text, signature, posted_at, reply_count, source_file, wayback_ts) VALUES (232, 153437, 1, 341, '答ART先生我的小资观', '首先感谢ART兄弟在百忙之中，不辞辛劳为不才所坐的文章，拜读后发现ART果然乃超级大才子也，文笔诙谐生动，幽默有趣，佩服佩服。
<br>
<br>马屁拍完了，忍不住还是要说上几句，以修正群众们对洒家的误解之处。
<br>群众们大都认为俺是一个楞头楞脑的愤怒青年，对小资抱有不共戴天的深仇大恨，其实非也非也。俺确确实实与满大街的小资们没什么过节，俺真正嗤之以鼻不屑甚至讨厌的不是小资，而是伪小资！当然我不排除在小资群体中的那部分确实有高人一筹的学识与修养的社会精英一族，然而这部分人的数量在时下中国社会中是微乎其微的，更多的人是举着小资的牌子大喊大叫招摇过市刚刚脱贫致富的城市农民。
<br>
<br>我为什么得出这个结论呢，各位看官听我慢慢道来。
<br>
<br>我们口中的小资与在政治课上的学到的中小资产阶级是两个不同的概念。后者是与他所掌握的生产资料以及他所享有的生活资料来定性的。而前者则不然，他除了要一定的物资基础外，更重要还在他的精神以及内涵方面。而伪小资的致命弱点就在这个方面。不要以为知道几个咖啡的牌子和几个爵士乐队的名字就能往小资的队伍里钻了。有的人（可以是非小资）中国字都认不全就给自己取了若干个英文名字了，什么安东尼亚历山大大了（还好没听说有人取爱新觉罗），全然忘了自己身份证上的大名--徐大毛或者张大民。还有的人动动就吐一口夹生的国语英语大杂烩：给我一长PAPER了，晚上去哪里HAPPY了诸如此类。其实我们在电视剧中看到香港人之所以有这样的说法，并不是他们想标榜自己有多少的英语词汇量，主要的原因是他们的国语本身就不好。这一点俺是深有体会的，俺们公司有一次来了个新加坡的工人维修机器，他使唤我们去拿工具时，费了半天劲也没能说出那工具的名称，最后他只好解释说他只知道那玩意的英文名称，中文他实在不知道怎么说。我们再回头看看那些动不动就口吐莲花的小资是多么的无知可笑。鲁迅老人家称这伙人为“西崽”，有着不可一世的骄横与自我膨胀感，觉得自己学贯中西，身兼两者之长，洋人及国人都不在他们眼里。其实我这么说还是夸他们了，绝大多数恐怕还是不学无术的小混混罢了。
<br>社会发展的现在，出现了一群被称为小资的群体，其实这更是一件好事。但这样一个阶层的出现是需要一定的外部环境的，首先要有适合他扎根的土壤，其次还要有能促进他生长发展的阳光及养料。而我们现在这个环境绝对还不存在这样的条件，至少在我们这个贫瘠的土壤里还长不出郁郁葱葱的小资灌木来。我们现在生存的土壤里还残留了多少无用甚至有毒的化学物质啊！类似于明哲保身的我们称之为优秀的文化传统的处世哲学至今还在我们的血液里流淌着，这与崇尚自由凸现自我的小资主义是多么格格不入啊。（未完待续）', '首先感谢ART兄弟在百忙之中，不辞辛劳为不才所坐的文章，拜读后发现ART果然乃超级大才子也，文笔诙谐生动，幽默有趣，佩服佩服。

马屁拍完了，忍不住还是要说上几句，以修正群众们对洒家的误解之处。

群众们大都认为俺是一个楞头楞脑的愤怒青年，对小资抱有不共戴天的深仇大恨，其实非也非也。俺确确实实与满大街的小资们没什么过节，俺真正嗤之以鼻不屑甚至讨厌的不是小资，而是伪小资！当然我不排除在小资群体中的那部分确实有高人一筹的学识与修养的社会精英一族，然而这部分人的数量在时下中国社会中是微乎其微的，更多的人是举着小资的牌子大喊大叫招摇过市刚刚脱贫致富的城市农民。

我为什么得出这个结论呢，各位看官听我慢慢道来。

我们口中的小资与在政治课上的学到的中小资产阶级是两个不同的概念。后者是与他所掌握的生产资料以及他所享有的生活资料来定性的。而前者则不然，他除了要一定的物资基础外，更重要还在他的精神以及内涵方面。而伪小资的致命弱点就在这个方面。不要以为知道几个咖啡的牌子和几个爵士乐队的名字就能往小资的队伍里钻了。有的人（可以是非小资）中国字都认不全就给自己取了若干个英文名字了，什么安东尼亚历山大大了（还好没听说有人取爱新觉罗），全然忘了自己身份证上的大名--徐大毛或者张大民。还有的人动动就吐一口夹生的国语英语大杂烩：给我一长PAPER了，晚上去哪里HAPPY了诸如此类。其实我们在电视剧中看到香港人之所以有这样的说法，并不是他们想标榜自己有多少的英语词汇量，主要的原因是他们的国语本身就不好。这一点俺是深有体会的，俺们公司有一次来了个新加坡的工人维修机器，他使唤我们去拿工具时，费了半天劲也没能说出那工具的名称，最后他只好解释说他只知道那玩意的英文名称，中文他实在不知道怎么说。我们再回头看看那些动不动就口吐莲花的小资是多么的无知可笑。鲁迅老人家称这伙人为“西崽”，有着不可一世的骄横与自我膨胀感，觉得自己学贯中西，身兼两者之长，洋人及国人都不在他们眼里。其实我这么说还是夸他们了，绝大多数恐怕还是不学无术的小混混罢了。

社会发展的现在，出现了一群被称为小资的群体，其实这更是一件好事。但这样一个阶层的出现是需要一定的外部环境的，首先要有适合他扎根的土壤，其次还要有能促进他生长发展的阳光及养料。而我们现在这个环境绝对还不存在这样的条件，至少在我们这个贫瘠的土壤里还长不出郁郁葱葱的小资灌木来。我们现在生存的土壤里还残留了多少无用甚至有毒的化学物质啊！类似于明哲保身的我们称之为优秀的文化传统的处世哲学至今还在我们的血液里流淌着，这与崇尚自由凸现自我的小资主义是多么格格不入啊。（未完待续）', NULL, '2002-03-14 19:19:00', 20, '20020406015500_bbsid_153437_board_1_0e5c76a030.html', '20020406015500');
